if (! function_exists('text_ngram_analyzer')) {
    function text_ngram_analyzer($text, $n = null, $mode = null, $max_results = null, $min_freq = null)
    {
        $n = isset($n) ? max(1, min(10, (int)$n)) : 3;
        $mode = isset($mode) ? $mode : 'char';
        $max_results = isset($max_results) ? (int)$max_results : 50;
        $min_freq = isset($min_freq) ? max(1, (int)$min_freq) : 1;

        if (empty(trim($text))) {
            return json_encode(['error' => 'Text cannot be empty']);
        }

        $ngrams = [];

        if ($mode === 'word') {
            $words = preg_split('/\s+/', trim($text));
            $words = array_values(array_filter($words, function($w) { return $w !== ''; }));
            $total = count($words);
            if ($total < $n) {
                return json_encode(['error' => "Text has only $total words, need at least $n for {$n}-grams"]);
            }
            $totalNgrams = $total - $n + 1;
            for ($i = 0; $i < $totalNgrams; $i++) {
                $gram = implode(' ', array_slice($words, $i, $n));
                $ngrams[$gram] = isset($ngrams[$gram]) ? $ngrams[$gram] + 1 : 1;
            }
        } else {
            // character n-grams
            $cleaned = $text;
            $len = mb_strlen($cleaned);
            if ($len < $n) {
                return json_encode(['error' => "Text has only $len characters, need at least $n for {$n}-grams"]);
            }
            $totalNgrams = $len - $n + 1;
            for ($i = 0; $i < $totalNgrams; $i++) {
                $gram = mb_substr($cleaned, $i, $n);
                $ngrams[$gram] = isset($ngrams[$gram]) ? $ngrams[$gram] + 1 : 1;
            }
        }

        // Filter by min_freq
        $ngrams = array_filter($ngrams, function($freq) use ($min_freq) {
            return $freq >= $min_freq;
        });

        if (empty($ngrams)) {
            return json_encode(['error' => 'No n-grams matched the minimum frequency threshold']);
        }

        // Sort by frequency descending, then alphabetically
        arsort($ngrams);

        $totalCount = array_sum($ngrams);
        $uniqueCount = count($ngrams);

        // Slice
        if ($max_results > 0 && $uniqueCount > $max_results) {
            $ngrams = array_slice($ngrams, 0, $max_results, true);
        }

        $results = [];
        foreach ($ngrams as $gram => $freq) {
            $results[] = [
                'ngram' => $gram,
                'frequency' => $freq,
                'percentage' => round($freq / $totalCount * 100, 2)
            ];
        }

        $modeLabel = $mode === 'word' ? 'word' : 'character';

        return json_encode([
            'mode' => $modeLabel,
            'n' => $n,
            'total_ngrams_sampled' => $totalCount,
            'unique_ngrams' => $uniqueCount,
            'shown' => count($results),
            'min_frequency' => $min_freq,
            'ngrams' => $results
        ]);
    }
